/**
 * Wrap-up keyword list matched against the most recent commit subject by the
 * pre-compact-task-done-prompt hook (#1469 / #1477).
 *
 * Conservative — only signals that strongly indicate "a unit of work just
 * closed". Generic conventional-commit prefixes (`feat:`, `fix:`, `chore:`)
 * are intentionally excluded because they fire on routine mid-task commits.
 */
export const BREAKPOINT_KEYWORDS = [
  // Issue / PR lifecycle
  'closes #',
  'closes#',
  'close #',
  'fixes #',
  'fixes#',
  'fix #',
  'resolves #',
  'resolves#',
  'merge pull request',
  'merged',
  // Release / deploy
  'released',
  'shipped',
  'deployed',
  'chore(main): release',
  'chore: release',
  // PR ops
  'pushed',
  'pr merge',
  'gh pr merge',
  'squash',
  // Direction marker (handoff summaries)
  'main →',
];

/** Case-insensitive substring match against the keyword list. */
export function matchesBreakpoint(subject: string): boolean {
  if (!subject) return false;
  const lower = subject.toLowerCase();
  return BREAKPOINT_KEYWORDS.some(kw => lower.includes(kw));
}
